class Solution {
    public int minimumOneBitOperations(int n) {
        int res = 0;
        while (n != 0) {
            if ((n & 1) == 1) {
                res++;
            }
            n = (n & ~(n - 1)) | ((n & (n - 1)) >> 1);
        }
        return res;
    }
}
